parameters.jsCode:
// Process Health Score and Generate Retention Code
const customer = $('Fetch Customer Data').first().json;
const analysis = JSON.parse($('AI Health Score Analysis').first().json.message.content);

// Generate unique retention code for high-risk customers
const generateRetentionCode = (riskLevel, plan) => {
  const prefix = riskLevel === 'high' ? 'SAVE' : 'THANK';
  const planCode = plan.substring(0, 3).toUpperCase();
  const random = Math.floor(Math.random() * 9000) + 1000;
  return `${prefix}-${planCode}-${random}`;
};

// Calculate discount based on risk and plan value
const getDiscount = (riskLevel, plan) => {
  if (riskLevel === 'high') return plan === 'Enterprise' ? 25 : 20;
  if (riskLevel === 'medium') return 10;
  return 0;
};

return [{
  json: {
    ...customer,
    ...analysis,
    retention_code: generateRetentionCode(analysis.risk_level, customer.plan),
    discount_percentage: getDiscount(analysis.risk_level, customer.plan),
    code_valid_days: analysis.risk_level === 'high' ? 14 : 30,
    analyzed_at: $now.toISO()
  }
}];

